{"command": "cd /tmp_workspace && python3 -c "
# Also verify the scheduled.ics new events have correct local times
raw = open('results/scheduled.ics').read()
lines = raw.splitlines()
in_ev = False
cur = {}
new_events = []
for line in lines:
    if line == 'BEGIN:VEVENT':
        in_ev = True
        cur = {}
    elif line == 'END:VEVENT':
        if cur.get('uid','').startswith('new-'):
            new_events.append(cur)
        in_ev = False
    elif in_ev:
        if line.startswith('UID:'): cur['uid'] = line[4:]
        elif line.startswith('SUMMARY:'): cur['summary'] = line[8:]
        elif line.startswith('DTSTART:'): cur['start'] = line[8:]
        elif line.startswith('DTEND:'): cur['end'] = line[6:]
        elif line.startswith('PRIORITY:'): cur['priority'] = line[9:]

from datetime import datetime, timezone
from zoneinfo import ZoneInfo
TZ = ZoneInfo('Asia/Shanghai')
UTC = timezone.utc

def parse_utc(s):
    s = s.rstrip('Z')
    return datetime.strptime(s, '%Y%m%dT%H%M%S').replace(tzinfo=UTC)

print('New events in CST:')
for ev in new_events:
    s = parse_utc(ev['start']).astimezone(TZ).strftime('%Y-%m-%d %H:%M')
    e = parse_utc(ev['end']).astimezone(TZ).strftime('%H:%M')
    print(f'  [{ev[\"priority\"]}] {ev[\"uid\"]}: {ev[\"summary\"]} @ {s}-{e} CST')
"
